import{_ as t,c as a,m as e,a as r,t as o,U as n,o as i}from"./chunks/framework.9QHaLlVJ.js";const E=JSON.parse('{"title":"StorageClass 详解","description":"","frontmatter":{"title":"StorageClass 详解"},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/StorageClass/StorageClass.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/StorageClass/StorageClass.md","lastUpdated":1705214817000}'),l={name:"doc/DevOps/Kubernetes/基础/StorageClass/StorageClass.md"},d={id:"frontmatter-title",tabindex:"-1"},c=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),p=n(`<p>本文介绍了 Kubernetes 中 <code>StorageClass</code> 的概念。在阅读本文之前建议先熟悉 <a href="https://kubernetes.io/docs/concepts/storage/volumes" target="_blank" rel="noreferrer">卷</a> 和 <a href="https://kubernetes.io/docs/concepts/storage/persistent-volumes" target="_blank" rel="noreferrer">Persistent Volume（持久卷）</a>。</p><h2 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h2><p><code>StorageClass</code> 为管理员提供了描述存储 &quot;class（类）&quot; 的方法。 不同的 class 可能会映射到不同的服务质量等级或备份策略，或由群集管理员确定的任意策略。 Kubernetes 本身不清楚各种 class 代表的什么。这个概念在其他存储系统中有时被称为“配置文件”。</p><h2 id="storageclass-资源" tabindex="-1">StorageClass 资源 <a class="header-anchor" href="#storageclass-资源" aria-label="Permalink to &quot;StorageClass 资源&quot;">​</a></h2><p><code>StorageClass</code> 中包含 <code>provisioner</code>、<code>parameters</code> 和 <code>reclaimPolicy</code> 字段，当 class 需要动态分配 <code>PersistentVolume</code> 时会使用到。</p><p><code>StorageClass</code> 对象的名称很重要，用户使用该类来请求一个特定的方法。 当创建 <code>StorageClass</code> 对象时，管理员设置名称和其他参数，一旦创建了对象就不能再对其更新。</p><p>管理员可以为没有申请绑定到特定 class 的 PVC 指定一个默认的 <code>StorageClass</code> ： 更多详情请参阅 <a href="https://kubernetes.io/docs/concepts/storage/persistent-volumes/#persistentvolumeclaims" target="_blank" rel="noreferrer"><code>PersistentVolumeClaim</code> 章节</a>。</p><div class="language-yaml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">StorageClass</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">storage.k8s.io/v1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">standard</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">provisioner</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">kubernetes.io/aws-ebs</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">parameters</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gp2</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">reclaimPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Retain</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">mountOptions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">debug</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h3 id="provisioner-存储分配器" tabindex="-1">Provisioner（存储分配器） <a class="header-anchor" href="#provisioner-存储分配器" aria-label="Permalink to &quot;Provisioner（存储分配器）&quot;">​</a></h3><p>Storage class 有一个分配器，用来决定使用哪个卷插件分配 PV。该字段必须指定。</p><table><thead><tr><th>Volume Plugin</th><th>Internal Provisioner</th><th>Config Example</th></tr></thead><tbody><tr><td>AWSElasticBlockStore</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#aws" target="_blank" rel="noreferrer">AWS</a></td></tr><tr><td>AzureFile</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#azure-file" target="_blank" rel="noreferrer">Azure File</a></td></tr><tr><td>AzureDisk</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#azure-disk" target="_blank" rel="noreferrer">Azure Disk</a></td></tr><tr><td>CephFS</td><td>-</td><td>-</td></tr><tr><td>Cinder</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#openstack-cinder" target="_blank" rel="noreferrer">OpenStack Cinder</a></td></tr><tr><td>FC</td><td>-</td><td>-</td></tr><tr><td>FlexVolume</td><td>-</td><td>-</td></tr><tr><td>Flocker</td><td>✓</td><td>-</td></tr><tr><td>GCEPersistentDisk</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#gce" target="_blank" rel="noreferrer">GCE</a></td></tr><tr><td>Glusterfs</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#glusterfs" target="_blank" rel="noreferrer">Glusterfs</a></td></tr><tr><td>iSCSI</td><td>-</td><td>-</td></tr><tr><td>PhotonPersistentDisk</td><td>✓</td><td>-</td></tr><tr><td>Quobyte</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#quobyte" target="_blank" rel="noreferrer">Quobyte</a></td></tr><tr><td>NFS</td><td>-</td><td>-</td></tr><tr><td>RBD</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#ceph-rbd" target="_blank" rel="noreferrer">Ceph RBD</a></td></tr><tr><td>VsphereVolume</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#vsphere" target="_blank" rel="noreferrer">vSphere</a></td></tr><tr><td>PortworxVolume</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#portworx-volume" target="_blank" rel="noreferrer">Portworx Volume</a></td></tr><tr><td>ScaleIO</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#scaleio" target="_blank" rel="noreferrer">ScaleIO</a></td></tr><tr><td>StorageOS</td><td>✓</td><td><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/#storageos" target="_blank" rel="noreferrer">StorageOS</a></td></tr></tbody></table><p>您不限于指定此处列出的&quot;内置&quot;分配器（其名称前缀为 kubernetes.io 并打包在 Kubernetes 中）。 您还可以运行和指定外部分配器，这些独立的程序遵循由 Kubernetes 定义的 <a href="https://git.k8s.io/community/contributors/design-proposals/storage/volume-provisioning.md" target="_blank" rel="noreferrer">规范</a>。 外部供应商的作者完全可以自由决定他们的代码保存于何处、打包方式、运行方式、使用的插件（包括Flex）等。 代码仓库 <a href="https://github.com/kubernetes-incubator/external-storage" target="_blank" rel="noreferrer">kubernetes-incubator/external-storage</a> 包含一个用于为外部分配器编写功能实现的类库，以及各种社区维护的外部分配器。</p><p>例如，NFS 没有内部分配器，但可以使用外部分配器。一些外部分配器在代码仓库 <a href="https://github.com/kubernetes-incubator/external-storage" target="_blank" rel="noreferrer">kubernetes-incubator/external-storage</a> 中。 也有第三方存储供应商提供自己的外部分配器。</p><p>关于内置的 StorageClass 的配置请参考 <a href="https://kubernetes.io/docs/concepts/storage/storage-classes/" target="_blank" rel="noreferrer">Storage Classes</a>。</p><h3 id="回收策略" tabindex="-1">回收策略 <a class="header-anchor" href="#回收策略" aria-label="Permalink to &quot;回收策略&quot;">​</a></h3><p>由 storage class 动态创建的 Persistent Volume 会在的 <code>reclaimPolicy</code> 字段中指定回收策略，可以是 <code>Delete</code> 或者 <code>Retain</code>。如果 <code>StorageClass</code> 对象被创建时没有指定 <code>reclaimPolicy</code> ，它将默认为 <code>Delete</code>。</p><p>通过 storage class 手动创建并管理的 Persistent Volume 会使用它们被创建时指定的回收政策。</p><h3 id="挂载选项" tabindex="-1">挂载选项 <a class="header-anchor" href="#挂载选项" aria-label="Permalink to &quot;挂载选项&quot;">​</a></h3><p>由 storage class 动态创建的 Persistent Volume 将使用 class 中 <code>mountOptions</code> 字段指定的挂载选项。</p><p>如果卷插件不支持挂载选项，却指定了该选项，则分配操作失败。 安装选项在 class 和 PV 上都不会做验证，所以如果挂载选项无效，那么这个 PV 就会失败。</p><h2 id="参数" tabindex="-1">参数 <a class="header-anchor" href="#参数" aria-label="Permalink to &quot;参数&quot;">​</a></h2><p>Storage class 具有描述属于 storage class 卷的参数。取决于<code>分配器</code>，可以接受不同的参数。 例如，参数 <code>type</code> 的值 <code>io1</code> 和参数 <code>iopsPerGB</code> 特定于 EBS PV。当参数被省略时，会使用默认值。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://kubernetes.io/docs/concepts/storage/storage-classes/" target="_blank" rel="noreferrer">https://kubernetes.io/docs/concepts/storage/storage-classes/</a></li></ul>`,24);function h(s,k,g,u,b,m){return i(),a("div",null,[e("h1",d,[r(o(s.$frontmatter.title)+" ",1),c]),p])}const _=t(l,[["render",h]]);export{E as __pageData,_ as default};
